+
+    const nextConfig: PoltergeistConfig = {
+      ...baseConfig,
+      targets: [
+        { name: 'two', type: 'custom', enabled: true, watchPaths: ['.'], buildCommand: 'echo two' },
+        {
+          name: 'three',
+          type: 'custom',
+          enabled: true,
+          watchPaths: ['.'],
+          buildCommand: 'echo three',
+        },
+      ],
+    };
